import{_ as c,C as d,o as r,c as p,a3 as n,b as i,w as a,a as t,E as l,a4 as s}from"./chunks/framework.C49Ar5GK.js";const R=JSON.parse('{"title":"入口与初始化：对象在什么时候出现","description":"从 Hydra main、Ray runtime env、TaskRunnerV1 到 PPOTrainer 装配，理解 veRL 启动时序和角色条件","frontmatter":{"title":"入口与初始化：对象在什么时候出现","description":"从 Hydra main、Ray runtime env、TaskRunnerV1 到 PPOTrainer 装配，理解 veRL 启动时序和角色条件","lesson":{"stage":"04 · 源码","order":15,"time":"40–60 分钟","level":"源码进阶","question":"一条命令怎样变成 Ray actor、训练 Worker、推理 server 和可运行的训练循环？"}},"headers":[],"relativePath":"internals/entry-and-init.md","filePath":"internals/entry-and-init.md","lastUpdated":null}'),u={name:"internals/entry-and-init.md"};function A(E,e,_,h,m,f){const o=d("Mermaid");return r(),p("div",null,[e[2]||(e[2]=n('<h1 id="入口与初始化-对象在什么时候出现" tabindex="-1">入口与初始化：对象在什么时候出现 <a class="header-anchor" href="#入口与初始化-对象在什么时候出现" aria-label="Permalink to &quot;入口与初始化：对象在什么时候出现&quot;">​</a></h1><p>入口阶段决定最终运行的并不是某个 YAML 文件，而是 Hydra defaults、命令行 override、环境变量和自动设备设置共同解析出的配置。</p><h2 id="先用人话-启动不是-创建一个-trainer" tabindex="-1">先用人话：启动不是“创建一个 Trainer” <a class="header-anchor" href="#先用人话-启动不是-创建一个-trainer" aria-label="Permalink to &quot;先用人话：启动不是“创建一个 Trainer”&quot;">​</a></h2><p>它更像开工前装配工厂：先定最终订单（resolved config），再让 Ray 建控制进程，初始化共享数据通道，按算法需要创建 actor/reference/critic/reward 角色，启动 rollout server，建立权重同步连接，最后才把 AgentLoop 交给 <code>fit()</code>。任何前置对象未就绪，训练 step 都还没开始。</p><h2 id="启动时序" tabindex="-1">启动时序 <a class="header-anchor" href="#启动时序" aria-label="Permalink to &quot;启动时序&quot;">​</a></h2>',5)),(r(),i(s,null,{default:a(()=>[l(o,{id:"mermaid-15",class:"mermaid",graph:"sequenceDiagram%0A%20%20%20%20participant%20CLI%20as%20CLI%20%2F%20Hydra%0A%20%20%20%20participant%20M%20as%20main()%0A%20%20%20%20participant%20RP%20as%20run_ppo()%0A%20%20%20%20participant%20Ray%20as%20Ray%0A%20%20%20%20participant%20T%20as%20TaskRunnerV1%0A%20%20%20%20participant%20P%20as%20PPOTrainer%0A%20%20%20%20participant%20Q%20as%20TransferQueue%0A%20%20%20%20participant%20A%20as%20AgentLoopManager%0A%0A%20%20%20%20CLI-%3E%3EM%3A%20%E7%BB%84%E5%90%88%20ppo_trainer%20%2B%20overrides%0A%20%20%20%20M-%3E%3EM%3A%20auto_set_device%20%2F%20validate_config%0A%20%20%20%20M-%3E%3ERP%3A%20config%2C%20TaskRunnerV1%0A%20%20%20%20RP-%3E%3ERP%3A%20%E8%AE%BE%E7%BD%AE%E7%A1%AE%E5%AE%9A%E6%80%A7%E7%8E%AF%E5%A2%83%E5%8F%98%E9%87%8F%0A%20%20%20%20RP-%3E%3ERay%3A%20ray.init(runtime_env)%0A%20%20%20%20Ray-%3E%3ET%3A%20%E5%88%9B%E5%BB%BA%E8%BF%9C%E7%AB%AF%20TaskRunner%0A%20%20%20%20T-%3E%3EQ%3A%20enable%20%2B%20init%0A%20%20%20%20T-%3E%3EP%3A%20%E9%80%89%E6%8B%A9%20trainer_mode%EF%BC%8C%E6%9E%84%E9%80%A0%E5%B9%B6%20init%0A%20%20%20%20P-%3E%3EP%3A%20dataloader%20%2F%20pools%20%2F%20WorkerGroups%0A%20%20%20%20P-%3E%3EP%3A%20reward%20%2F%20LLM%20server%20%2F%20checkpoint%20engine%0A%20%20%20%20T-%3E%3EA%3A%20create(llm%20client%2C%20reward%20handles)%0A%20%20%20%20T-%3E%3EP%3A%20fit(A)%0A"})]),fallback:a(()=>[...e[0]||(e[0]=[t(" Loading... ",-1)])]),_:1})),e[3]||(e[3]=n('<h2 id="main-先校验角色-再选版本" tabindex="-1"><code>main()</code>：先校验角色，再选版本 <a class="header-anchor" href="#main-先校验角色-再选版本" aria-label="Permalink to &quot;`main()`：先校验角色，再选版本&quot;">​</a></h2><p><a href="https://github.com/verl-project/verl/blob/e5687fce0516d31e1fdc4580499074a9bd94c751/verl/trainer/main_ppo.py" target="_blank" rel="noreferrer"><code>main_ppo.py</code></a> 中 <code>main()</code> 做三件关键事：</p><ol><li>在 Ascend 环境自动设置 <code>trainer.device=npu</code>；</li><li>根据配置推导是否需要 reference policy 和 critic，再调用 <code>validate_config</code>；</li><li><code>trainer.use_v1=true</code> 时选择 <code>TaskRunnerV1</code>，否则进入有弃用提示的 V0。</li></ol><p>因此“配置里 critic.enable=false”是否足够，要以 <code>need_critic(config)</code> 的推导和校验结果为准。算法选择与角色存在性是关联约束。</p><h2 id="run-ppo-环境必须在-ray-actor-之前确定" tabindex="-1"><code>run_ppo()</code>：环境必须在 Ray actor 之前确定 <a class="header-anchor" href="#run-ppo-环境必须在-ray-actor-之前确定" aria-label="Permalink to &quot;`run_ppo()`：环境必须在 Ray actor 之前确定&quot;">​</a></h2><p>若 rollout 或 reward-model rollout 开启 <code>full_determinism</code>，代码在 <code>ray.init()</code> 之前设置 <code>VERL_FULL_DETERMINISM</code>、<code>VLLM_BATCH_INVARIANT</code> 与 <code>PYTHONHASHSEED</code>，再由 Ray runtime env 传播到 actors。</p><p>这是分布式调试的通则：只在 driver shell 中晚设环境变量，不代表已经启动的 Ray worker 会收到它。多机变量也应在各节点加入集群前准备好。</p><p><code>run_ppo()</code> 还会合并用户 <code>ray_kwargs.ray_init.runtime_env</code>；TQ 启用时添加 <code>TRANSFER_QUEUE_ENABLE=1</code>。若配置 nsys profiling steps，则给 TaskRunner 附加 Nsight runtime option。</p><h2 id="taskrunnerv1-run-建立-v1-边界" tabindex="-1"><code>TaskRunnerV1.run()</code>：建立 V1 边界 <a class="header-anchor" href="#taskrunnerv1-run-建立-v1-边界" aria-label="Permalink to &quot;`TaskRunnerV1.run()`：建立 V1 边界&quot;">​</a></h2><p>执行顺序是：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>get_trainer_cls(trainer_mode)</span></span>\n<span class="line"><span>→ transfer_queue.enable = true</span></span>\n<span class="line"><span>→ resolve/print config</span></span>\n<span class="line"><span>→ tq.init(config.transfer_queue)</span></span>\n<span class="line"><span>→ trainer.init()</span></span>\n<span class="line"><span>→ AgentLoopManagerTQ.create(...)</span></span>\n<span class="line"><span>→ trainer.fit(...)</span></span>\n<span class="line"><span>→ finally: tq.close()</span></span></code></pre></div><p><code>finally</code> 关闭 TQ 意味着初始化后任何异常都应保留上游日志；不要只看最后的 close/connection error，就把它误判为根因。</p><h2 id="ppotrainer-setup-按依赖顺序装配" tabindex="-1"><code>PPOTrainer._setup()</code>：按依赖顺序装配 <a class="header-anchor" href="#ppotrainer-setup-按依赖顺序装配" aria-label="Permalink to &quot;`PPOTrainer._setup()`：按依赖顺序装配&quot;">​</a></h2>',13)),(r(),i(s,null,{default:a(()=>[l(o,{id:"mermaid-67",class:"mermaid",graph:"flowchart%20TD%0A%20%20%20%20A%5Btokenizer%20%2B%20dataloader%5D%20--%3E%20B%5BResourcePoolManager%5D%0A%20%20%20%20B%20--%3E%20C%5BActor%2FRef%20WorkerGroup%5D%0A%20%20%20%20B%20--%3E%20D%5BCritic%20WorkerGroup%20%E5%8F%AF%E9%80%89%5D%0A%20%20%20%20C%20--%3E%20E%5BRewardLoopManager%5D%0A%20%20%20%20C%20--%3E%20F%5BLLMServerManager%5D%0A%20%20%20%20F%20--%3E%20G%5BCheckpointEngineManager%5D%0A%20%20%20%20G%20--%3E%20H%5Bsleep%20replicas%5D%0A%20%20%20%20H%20--%3E%20I%5Bload%20checkpoint%5D%0A%20%20%20%20I%20--%3E%20J%5Bon_init_end%5D%0A"})]),fallback:a(()=>[...e[1]||(e[1]=[t(" Loading... ",-1)])]),_:1})),e[4]||(e[4]=n('<p>具体要点：</p><ul><li>actor role 根据映射选择 <code>ActorRolloutRef</code> 或 <code>ActorRollout</code>；</li><li>critic 只在 <code>need_critic</code> 为真时创建并设置 value loss；</li><li>LoRA 或 adapter 场景可以让 reference 复用 actor、通过关闭 adapter 计算；</li><li>RewardLoopManager 可以有独立 RM 资源，也可以只执行规则奖励；</li><li>LLMServerManager 从 actor worker 与 rollout resource pool 创建推理副本；</li><li>CheckpointEngineManager 连接 actor WorkerGroup 与这些 replicas，承担权重同步。</li></ul><p>同步 trainer 的 <code>on_init_end()</code> 会在 checkpoint 加载后先同步一次权重。之后每个 step 的同步时机见<a href="./rollout-to-update">从推理到训练</a>。</p><h2 id="初始化故障的定位顺序" tabindex="-1">初始化故障的定位顺序 <a class="header-anchor" href="#初始化故障的定位顺序" aria-label="Permalink to &quot;初始化故障的定位顺序&quot;">​</a></h2><ol><li>查看打印出来的 resolved config，确认 mode、后端、模型路径和资源数；</li><li>找第一个 worker/actor 异常，而不是 Ray 汇总异常的最后一行；</li><li>检查每个节点能否访问模型、数据、日志与 checkpoint 路径；</li><li>对照 Ray resource demand 与集群实际 GPU/CPU 标签；</li><li>确认运行时导入的是当前源码而非另一份 site-packages。</li></ol><h2 id="建议断点与通关检查" tabindex="-1">建议断点与通关检查 <a class="header-anchor" href="#建议断点与通关检查" aria-label="Permalink to &quot;建议断点与通关检查&quot;">​</a></h2><p>第一次只在 <code>main()</code>、<code>run_ppo()</code>、<code>TaskRunnerV1.run()</code>、trainer <code>init()</code> 后各停一次，记录：当前进程、config 中 mode、已创建的 role、TQ 是否初始化。能解释环境变量为何必须在 <code>ray.init()</code> 前传播，并说明 sync trainer 首次权重同步发生在训练前，才算通过。</p><p>下一步：<a href="./rollout-to-update">从推理到训练</a>。</p>',8))])}const k=c(u,[["render",A]]);export{R as __pageData,k as default};
